module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const v = parseFloat(args.value) || 0;
const lo = Number.isFinite(parseFloat(args.min)) ? parseFloat(args.min) : 0;
const hi = Number.isFinite(parseFloat(args.max)) ? parseFloat(args.max) : 100;
const frac = Math.max(0, Math.min(1, (v - lo) / ((hi - lo) || 1)));
let color = args.color || 'var(--accent-color)';
if (String(args.zones) === 'true') color = frac < 0.6 ? '#16a34a' : frac < 0.85 ? '#f59e0b' : '#dc2626';
const R = 50, CX = 60, CY = 62;
const arcLen = Math.PI * R;
const ang = Math.PI * (1 - frac); // radians from +x axis
const nx = CX + (R - 10) * Math.cos(ang), ny = CY - (R - 10) * Math.sin(ang);
const track = `M${CX - R},${CY} A${R},${R} 0 0 1 ${CX + R},${CY}`;
const fmt = (x) => String(+(+x).toFixed(2));
// Flexibility params (defaults reproduce the original look exactly).
const gw = (args.width && String(args.width).trim()) || '260px';
const sw = Math.max(2, Math.min(20, parseFloat(args.thickness) || 9));
const showRange = String(args.showrange) !== 'false';
const al = String(args.align || 'center').toLowerCase();
const mx = al === 'left' ? '1rem auto 1rem 0' : al === 'right' ? '1rem 0 1rem auto' : '1rem auto';
return `\n\n<div class="mdp-mod-gauge" style="--gg-c:${color}; --gg-w:${gw}; --gg-sw:${sw}; margin:${mx};"><svg viewBox="0 0 120 78" preserveAspectRatio="xMidYMid meet">` +
  `<path d="${track}" class="mdp-gg-track"/>` +
  `<path d="${track}" class="mdp-gg-arc" style="stroke-dasharray:${(frac * arcLen).toFixed(1)} ${arcLen.toFixed(1)};"/>` +
  `<line x1="${CX}" y1="${CY}" x2="${nx.toFixed(1)}" y2="${ny.toFixed(1)}" class="mdp-gg-needle"/>` +
  `<circle cx="${CX}" cy="${CY}" r="3.5" class="mdp-gg-hub"/>` +
  (showRange ? `<text x="${CX - R}" y="${CY + 9}" class="mdp-gg-end" text-anchor="middle">${fmt(lo)}</text>` +
  `<text x="${CX + R}" y="${CY + 9}" class="mdp-gg-end" text-anchor="middle">${fmt(hi)}</text>` : '') +
  `</svg><div class="mdp-gg-value">${fmt(v)}${esc(args.unit || '')}</div>` +
  (args.label ? `<div class="mdp-gg-label">${esc(args.label)}</div>` : '') +
  `</div>\n\n`;
